            "content": "{\r\n  \"name\": \"behaviorsubject-demo\",\r\n  \"version\": \"0.0.0\",\r\n  \"scripts\": {\r\n    \"ng\": \"ng\",\r\n    \"start\": \"ng serve\",\r\n    \"build\": \"ng build\",\r\n    \"watch\": \"ng build --watch --configuration development\",\r\n    \"test\": \"ng test\"\r\n  },\r\n  \"private\": true,\r\n  \"dependencies\": {\r\n    \"@angular/animations\": \"^20.3.10\",\r\n    \"@angular/common\": \"^20.3.10\",\r\n    \"@angular/compiler\": \"^20.3.10\",\r\n    \"@angular/core\": \"^20.3.10\",\r\n    \"@angular/forms\": \"^20.3.10\",\r\n    \"@angular/platform-browser\": \"^20.3.10\",\r\n    \"@angular/platform-browser-dynamic\": \"^20.3.10\",\r\n    \"@angular/router\": \"^20.3.10\",\r\n    \"bootstrap\": \"^5.3.8\",\r\n    \"ng-bootstrap\": \"^0.46.0\",\r\n    \"rxjs\": \"~7.8.0\",\r\n    \"tslib\": \"^2.3.0\",\r\n    \"zone.js\": \"~0.15.1\"\r\n  },\r\n  \"devDependencies\": {\r\n    \"@angular-devkit/build-angular\": \"^20.3.9\",\r\n    \"@angular/cli\": \"^20.3.9\",\r\n    \"@angular/compiler-cli\": \"^20.3.10\",\r\n    \"@eslint/js\": \"^9.36.0\",\r\n    \"@types/jasmine\": \"~5.1.0\",\r\n    \"eslint\": \"^9.36.0\",\r\n    \"globals\": \"^16.4.0\",\r\n    \"jasmine-core\": \"~5.12.1\",\r\n    \"jiti\": \"^2.6.0\",\r\n    \"karma\": \"~6.4.0\",\r\n    \"karma-chrome-launcher\": \"~3.2.0\",\r\n    \"karma-coverage\": \"~2.2.0\",\r\n    \"karma-jasmine\": \"~5.1.0\",\r\n    \"karma-jasmine-html-reporter\": \"~2.1.0\",\r\n    \"typescript\": \"~5.9.3\",\r\n    \"typescript-eslint\": \"^8.46.4\"\r\n  }\r\n}\r\n"
