            "content": "{\r\n  \"name\": \"ngx-json-dynamic-forms\",\r\n  \"version\": \"1.0.0\",\r\n  \"license\": \"MIT\",\r\n  \"scripts\": {\r\n    \"ng\": \"ng\",\r\n    \"start\": \"ng serve\",\r\n    \"build\": \"ng build\",\r\n    \"watch\": \"ng build --watch --configuration development\",\r\n    \"test\": \"ng test\",\r\n    \"lib:watch\": \"ng build ngx-dynamic-forms --watch\",\r\n    \"tailwind:watch\": \"NODE_ENV=production  npx tailwindcss-cli@latest -c ./tailwind.config.js build -o ./projects/ngx-dynamic-forms/src/styles.css --watch\",\r\n    \"dev:app\": \"ng serve examples\",\r\n    \"dev\": \"npm-run-all --parallel tailwind:watch lib:watch \",\r\n    \"g:tailwind-safelist\": \"node generate-tailwind-safelist.js\"\r\n  },\r\n  \"private\": true,\r\n  \"dependencies\": {\r\n    \"@angular/animations\": \"^21.0.1\",\r\n    \"@angular/common\": \"^21.0.1\",\r\n    \"@angular/compiler\": \"^21.0.1\",\r\n    \"@angular/core\": \"^21.0.1\",\r\n    \"@angular/forms\": \"^21.0.1\",\r\n    \"@angular/platform-browser\": \"^21.0.1\",\r\n    \"@angular/platform-browser-dynamic\": \"^21.0.1\",\r\n    \"@angular/router\": \"^21.0.1\",\r\n    \"@tailwindcss/postcss\": \"^4.0.9\",\r\n    \"madge\": \"^8.0.0\",\r\n    \"ngx-dynamic-forms-factory\": \"^0.1.5\",\r\n    \"postcss\": \"^8.5.3\",\r\n    \"rxjs\": \"~7.8.0\",\r\n    \"tailwindcss\": \"^4.0.9\",\r\n    \"tslib\": \"^2.3.0\",\r\n    \"zone.js\": \"~0.15.0\"\r\n  },\r\n  \"devDependencies\": {\r\n    \"@angular-devkit/build-angular\": \"^21.0.1\",\r\n    \"@angular/cli\": \"^21.0.1\",\r\n    \"@angular/compiler-cli\": \"^21.0.1\",\r\n    \"@types/jasmine\": \"~5.1.0\",\r\n    \"jasmine-core\": \"~5.5.0\",\r\n    \"karma\": \"~6.4.0\",\r\n    \"karma-chrome-launcher\": \"~3.2.0\",\r\n    \"karma-coverage\": \"~2.2.0\",\r\n    \"karma-jasmine\": \"~5.1.0\",\r\n    \"karma-jasmine-html-reporter\": \"~2.1.0\",\r\n    \"ng-packagr\": \"^19.2.0\",\r\n    \"npm-run-all\": \"^4.1.5\",\r\n    \"typescript\": \"~5.9.3\"\r\n  }\r\n}\r\n"
