                "content": "{\r\n  \"name\": \"ng-http-caching\",\r\n  \"version\": \"20.0.1\",\r\n  \"description\": \"Cache for HTTP requests in Angular application.\",\r\n  \"repository\": {\r\n    \"type\": \"git\",\r\n    \"url\": \"git+https://github.com/nigrosimone/ng-http-caching.git\"\r\n  },\r\n  \"keywords\": [\r\n    \"angular\",\r\n    \"cache\",\r\n    \"interceptor\",\r\n    \"network\",\r\n    \"http\",\r\n    \"client\",\r\n    \"http-client\",\r\n    \"header\",\r\n    \"headers\",\r\n    \"interact\",\r\n    \"configuration\"\r\n  ],\r\n  \"author\": \"Simone Nigro <nigro.simone@gmail.com>\",\r\n  \"license\": \"MIT\",\r\n  \"bugs\": {\r\n    \"url\": \"https://github.com/nigrosimone/ng-http-caching/issues\"\r\n  },\r\n  \"homepage\": \"https://github.com/nigrosimone/ng-http-caching\",\r\n  \"scripts\": {\r\n    \"ng\": \"ng\",\r\n    \"start\": \"ng serve\",\r\n    \"build\": \"ng build\",\r\n    \"test\": \"ng test\",\r\n    \"lint\": \"ng lint\",\r\n    \"e2e\": \"ng e2e\",\r\n    \"start-proxy\": \"ng serve --proxy-config proxy.config.json\"\r\n  },\r\n  \"dependencies\": {\r\n    \"@angular/animations\": \"^20.0.2\",\r\n    \"@angular/common\": \"^20.0.2\",\r\n    \"@angular/compiler\": \"^20.0.2\",\r\n    \"@angular/core\": \"^20.0.2\",\r\n    \"@angular/forms\": \"^20.0.2\",\r\n    \"@angular/platform-browser\": \"^20.0.2\",\r\n    \"@angular/platform-browser-dynamic\": \"^20.0.2\",\r\n    \"@angular/router\": \"^20.0.2\",\r\n    \"rxjs\": \"^7.8.2\",\r\n    \"tslib\": \"^2.6.3\",\r\n    \"zone.js\": \"^0.15.1\"\r\n  },\r\n  \"devDependencies\": {\r\n    \"@angular-devkit/build-ng-packagr\": \"^0.1002.0\",\r\n    \"@angular-eslint/builder\": \"^20.0.0\",\r\n    \"@angular-eslint/eslint-plugin\": \"^20.0.0\",\r\n    \"@angular-eslint/eslint-plugin-template\": \"^20.0.0\",\r\n    \"@angular-eslint/schematics\": \"^20.0.0\",\r\n    \"@angular-eslint/template-parser\": \"^20.0.0\",\r\n    \"@angular/build\": \"^20.0.1\",\r\n    \"@angular/cli\": \"^20.0.1\",\r\n    \"@angular/compiler-cli\": \"^20.0.2\",\r\n    \"@types/jasmine\": \"^5.1.8\",\r\n    \"@types/jasminewd2\": \"^2.0.13\",\r\n    \"@types/node\": \"^22.15.30\",\r\n    \"@typescript-eslint/eslint-plugin\": \"^8.33.1\",\r\n    \"@typescript-eslint/parser\": \"^8.33.1\",\r\n    \"codelyzer\": \"^6.0.2\",\r\n    \"coveralls\": \"^3.1.1\",\r\n    \"eslint\": \"^8.56.0\",\r\n    \"jasmine-core\": \"^5.8.0\",\r\n    \"jasmine-spec-reporter\": \"^7.0.0\",\r\n    \"karma\": \"^6.4.4\",\r\n    \"karma-chrome-launcher\": \"^3.2.0\",\r\n    \"karma-coverage\": \"^2.2.1\",\r\n    \"karma-jasmine\": \"^5.1.0\",\r\n    \"karma-jasmine-html-reporter\": \"^2.1.0\",\r\n    \"ng-packagr\": \"^20.0.0\",\r\n    \"protractor\": \"~7.0.0\",\r\n    \"ts-node\": \"^10.9.2\",\r\n    \"tslint\": \"~6.1.0\",\r\n    \"typescript\": \"^5.8.3\"\r\n  },\r\n  \"engines\": {\r\n    \"node\": \">=12.13.0\"\r\n  }\r\n}\r\n"
