                "content": "{\r\n  \"name\": \"react-axios-typescript-example\",\r\n  \"version\": \"0.1.0\",\r\n  \"private\": true,\r\n  \"dependencies\": {\r\n    \"@testing-library/jest-dom\": \"^5.14.1\",\r\n    \"@testing-library/react\": \"^11.2.7\",\r\n    \"@testing-library/user-event\": \"^12.8.3\",\r\n    \"@types/jest\": \"^26.0.23\",\r\n    \"@types/node\": \"^12.20.15\",\r\n    \"@types/react\": \"^17.0.13\",\r\n    \"@types/react-dom\": \"^17.0.8\",\r\n    \"@types/react-router-dom\": \"^5.1.7\",\r\n    \"axios\": \"^1.13.2\",\r\n    \"bootstrap\": \"^4.6.0\",\r\n    \"react\": \"^17.0.2\",\r\n    \"react-dom\": \"^17.0.2\",\r\n    \"react-router-dom\": \"^5.2.0\",\r\n    \"react-scripts\": \"^0.0.0\",\r\n    \"typescript\": \"^4.3.5\",\r\n    \"web-vitals\": \"^1.1.2\"\r\n  },\r\n  \"scripts\": {\r\n    \"start\": \"react-scripts start\",\r\n    \"build\": \"react-scripts build\",\r\n    \"test\": \"react-scripts test\",\r\n    \"eject\": \"react-scripts eject\"\r\n  },\r\n  \"eslintConfig\": {\r\n    \"extends\": [\r\n      \"react-app\",\r\n      \"react-app/jest\"\r\n    ]\r\n  },\r\n  \"browserslist\": {\r\n    \"production\": [\r\n      \">0.2%\",\r\n      \"not dead\",\r\n      \"not op_mini all\"\r\n    ],\r\n    \"development\": [\r\n      \"last 1 chrome version\",\r\n      \"last 1 firefox version\",\r\n      \"last 1 safari version\"\r\n    ]\r\n  }\r\n}\r\n"
