            "readme": "# SpringBootMicroservices\n\nSpring Boot microservices demo with JPA, MySQL, and ModelMapper.\n\n## Tech Stack\n\n- Spring Boot 4.0\n- Spring Data JPA\n- Spring Web MVC\n- MySQL\n- ModelMapper 3.2\n- Java 25 / Maven\n\n## Running\n\n```bash\nmvn spring-boot:run\n```\n\nRequires MySQL.\n",
            "aboutTxt": "https://www.geeksforgeeks.org/springboot/java-spring-boot-microservices-example-step-by-step-guide/\r\n\r\nhttp://localhost:8080/employees/1\r\n{\"age\":\"33\",\"email\":\"email\",\"id\":1,\"name\":\"aaa\"}\r\n\r\n\r\nCREATE TABLE `microservices`.`employee` (\r\n  `id` INT NOT NULL AUTO_INCREMENT,\r\n  `name` VARCHAR(45) NULL,\r\n  `email` VARCHAR(45) NULL,\r\n  `age` VARCHAR(45) NULL,\r\n  PRIMARY KEY (`id`));\r\n\r\nINSERT INTO `microservices`.`employee` (`id`, `name`, `email`, `age`) VALUES ('1', 'aaa', 'email', '33');\r\n",
            "commentsTxt": null,
