              {
                "name": "pom.xml",
                "content": "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n<project xmlns=\"http://maven.apache.org/POM/4.0.0\"\r\n    xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\r\n    xsi:schemaLocation=\"http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd\">\r\n    <modelVersion>4.0.0</modelVersion>\r\n    <!-- Vaadin project from https://github.com/vaadin/skeleton-starter-flow-spring -->\r\n    <groupId>com.example</groupId>\r\n    <artifactId>spring-skeleton</artifactId>\r\n    <name>Project base for Spring Boot and Vaadin Flow</name>\r\n    <version>1.0-SNAPSHOT</version>\r\n    <packaging>jar</packaging>\r\n\r\n    <properties>\r\n        <java.version>21</java.version>\r\n        <vaadin.version>25.0.3</vaadin.version>\r\n    </properties>\r\n\r\n    <parent>\r\n        <groupId>org.springframework.boot</groupId>\r\n        <artifactId>spring-boot-starter-parent</artifactId>\r\n        <version>4.0.1</version>\r\n    </parent>\r\n\r\n    <repositories>\r\n        <repository>\r\n            <id>vaadin-prereleases</id>\r\n            <url>https://maven.vaadin.com/vaadin-prereleases</url>\r\n            <snapshots>\r\n                <enabled>true</enabled>\r\n            </snapshots>\r\n        </repository>\r\n        <repository>\r\n            <id>Vaadin Directory</id>\r\n            <url>https://maven.vaadin.com/vaadin-addons</url>\r\n            <snapshots>\r\n                <enabled>false</enabled>\r\n            </snapshots>\r\n        </repository>\r\n    </repositories>\r\n\r\n    <pluginRepositories>\r\n        <pluginRepository>\r\n            <id>vaadin-prereleases</id>\r\n            <url>https://maven.vaadin.com/vaadin-prereleases</url>\r\n            <snapshots>\r\n                <enabled>true</enabled>\r\n            </snapshots>\r\n        </pluginRepository>\r\n    </pluginRepositories>\r\n\r\n    <dependencyManagement>\r\n        <dependencies>\r\n            <dependency>\r\n                <groupId>com.vaadin</groupId>\r\n                <artifactId>vaadin-bom</artifactId>\r\n                <version>${vaadin.version}</version>\r\n                <type>pom</type>\r\n                <scope>import</scope>\r\n            </dependency>\r\n        </dependencies>\r\n    </dependencyManagement>\r\n\r\n    <dependencies>\r\n        <dependency>\r\n            <groupId>com.vaadin</groupId>\r\n            <!-- Replace artifactId with vaadin-core to use only free components -->\r\n            <artifactId>vaadin</artifactId>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>com.vaadin</groupId>\r\n            <artifactId>vaadin-spring-boot-starter</artifactId>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>org.springframework.boot</groupId>\r\n            <artifactId>spring-boot-starter-validation</artifactId>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>com.vaadin</groupId>\r\n            <artifactId>vaadin-dev</artifactId>\r\n            <optional>true</optional>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>org.springframework.boot</groupId>\r\n            <artifactId>spring-boot-devtools</artifactId>\r\n            <optional>true</optional>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>org.springframework.boot</groupId>\r\n            <artifactId>spring-boot-starter-test</artifactId>\r\n            <scope>test</scope>\r\n        </dependency>\r\n        <dependency>\r\n            <groupId>com.vaadin</groupId>\r\n            <artifactId>vaadin-testbench-junit6</artifactId>\r\n            <scope>test</scope>\r\n            <!-- Test-scoped dependencies are always considered \"optional\", but \r\n            their transitive dependencies may conflict with those from regular \r\n            optional dependencies if not explicitly marked as optional here. -->\r\n            <optional>true</optional>\r\n        </dependency>\r\n    </dependencies>\r\n\r\n    <build>\r\n        <defaultGoal>spring-boot:run</defaultGoal>\r\n        <plugins>\r\n            <plugin>\r\n                <groupId>org.springframework.boot</groupId>\r\n                <artifactId>spring-boot-maven-plugin</artifactId>\r\n            </plugin>\r\n            <plugin>\r\n                <groupId>com.vaadin</groupId>\r\n                <artifactId>vaadin-maven-plugin</artifactId>\r\n                <version>${vaadin.version}</version>\r\n                <executions>\r\n                    <execution>\r\n                        <goals>\r\n                            <goal>build-frontend</goal>\r\n                        </goals>\r\n                    </execution>\r\n                </executions>\r\n            </plugin>\r\n        </plugins>\r\n    </build>\r\n\r\n    <profiles>\r\n        <profile>\r\n            <id>it</id>\r\n            <build>\r\n                <plugins>\r\n                    <plugin>\r\n                        <groupId>org.springframework.boot</groupId>\r\n                        <artifactId>spring-boot-maven-plugin</artifactId>\r\n                        <executions>\r\n                            <execution>\r\n                                <id>start-spring-boot</id>\r\n                                <phase>pre-integration-test</phase>\r\n                                <goals>\r\n                                    <goal>start</goal>\r\n                                </goals>\r\n                            </execution>\r\n                            <execution>\r\n                                <id>stop-spring-boot</id>\r\n                                <phase>post-integration-test</phase>\r\n                                <goals>\r\n                                    <goal>stop</goal>\r\n                                </goals>\r\n                            </execution>\r\n                        </executions>\r\n                    </plugin>\r\n\r\n                    <!-- Runs the integration tests (*IT) after the server is started -->\r\n                    <plugin>\r\n                        <groupId>org.apache.maven.plugins</groupId>\r\n                        <artifactId>maven-failsafe-plugin</artifactId>\r\n                        <executions>\r\n                            <execution>\r\n                                <goals>\r\n                                    <goal>integration-test</goal>\r\n                                    <goal>verify</goal>\r\n                                </goals>\r\n                            </execution>\r\n                        </executions>\r\n                        <configuration>\r\n                            <trimStackTrace>false</trimStackTrace>\r\n                            <enableAssertions>true</enableAssertions>\r\n                        </configuration>\r\n                    </plugin>\r\n                </plugins>\r\n            </build>\r\n        </profile>\r\n\r\n    </profiles>\r\n</project>\r\n"
              }
