                "content": "{\r\n  \"name\": \"my-vue-app\",\r\n  \"private\": true,\r\n  \"version\": \"0.0.0\",\r\n  \"type\": \"module\",\r\n  \"scripts\": {\r\n    \"dev\": \"vite\",\r\n    \"build\": \"vue-tsc && vite build\",\r\n    \"preview\": \"vite preview\"\r\n  },\r\n  \"dependencies\": {\r\n    \"vue\": \"3.4.21\"\r\n  },\r\n  \"devDependencies\": {\r\n    \"@vitejs/plugin-vue\": \"5.0.4\",\r\n    \"autoprefixer\": \"10.4.19\",\r\n    \"postcss\": \"8.4.38\",\r\n    \"tailwindcss\": \"3.4.4\",\r\n    \"typescript\": \"5.2.2\",\r\n    \"vite\": \"5.2.0\",\r\n    \"vue-tsc\": \"2.0.6\"\r\n  }\r\n}\r\n"
