            "content": "{\n  \"name\": \"ecommerce-microservices\",\n  \"version\": \"1.0.0\",\n  \"description\": \"Backend-only e-commerce microservices app for learning purposes\",\n  \"private\": true,\n  \"scripts\": {\n    \"dev\": \"docker-compose up --build\",\n    \"down\": \"docker-compose down\",\n    \"logs\": \"docker-compose logs -f\",\n    \"clean\": \"docker-compose down -v --remove-orphans\",\n    \"k8s:build\": \"docker build -t user-service:local ./user-service && docker build -t product-service:local ./product-service && docker build -t order-service:local ./order-service && docker build -t api-gateway:local ./gateway && docker build -t frontend:local ./frontend\",\n    \"k8s:apply\": \"kubectl apply -f k8s/secrets.yaml -f k8s/configmaps -f k8s/mongodb -f k8s/deployments\",\n    \"k8s:delete\": \"kubectl delete -f k8s/deployments -f k8s/mongodb -f k8s/configmaps -f k8s/secrets.yaml\",\n    \"k8s:status\": \"kubectl get pods,services,pvc\"\n  }\n}\n"
